INSERT INTO `quiz_questions` (`id`, `question_text`, `explanation_correct`, `created_at`, `updated_at`, `deleted_at`) VALUES
	(41, 'Bagaimana mekanisme operasi pasar terbuka (open market operations) mempengaruhi tingkat suku bunga jangka pendek dan likuiditas perbankan?', 'Operasi pasar terbuka adalah instrumen utama bank sentral untuk mengatur likuiditas di sistem perbankan. Dengan membeli surat berharga pemerintah, bank sentral menambah likuiditas di pasar, sehingga jumlah uang beredar meningkat dan tekanan penawaran pinjaman menurunkan suku bunga jangka pendek. Sebaliknya, penjualan surat berharga menyerap likuiditas, meningkatkan suku bunga. Mekanisme ini penting untuk menyesuaikan kondisi moneter dengan target inflasi atau stabilitas keuangan.', '2026-03-28 14:30:19', '2026-03-28 14:30:19', NULL),
	(42, 'Jelaskan perbedaan antara standing lending facility dan standing deposit facility serta dampaknya terhadap kebijakan moneter.', 'Standing lending facility adalah fasilitas kredit darurat bagi bank komersial dengan suku bunga lebih tinggi dari pasar, bertujuan menjadi atap suku bunga jangka pendek. Standing deposit facility adalah fasilitas menempatkan kelebihan likuiditas di bank sentral dengan suku bunga lebih rendah dari pasar, bertindak sebagai lantai suku bunga. Kedua instrumen ini membatasi fluktuasi suku bunga antarbank (interbank) dan memberi bank sentral kendali atas batas bawah dan atas suku bunga jangka pendek, sehingga memengaruhi transmisi kebijakan moneter.', '2026-03-28 14:30:19', '2026-03-28 14:30:19', NULL),
	(43, 'Apa risiko utama yang dihadapi bank sentral jika menggunakan suku bunga negatif sebagai alat kebijakan moneter?', 'Suku bunga negatif bertujuan mendorong bank dan konsumen untuk meningkatkan pinjaman dan pengeluaran. Namun, risiko termasuk menekan profitabilitas bank komersial, mendorong penarikan dana tunai (cash hoarding), dan menimbulkan distorsi pasar uang. Selain itu, suku bunga negatif bisa memicu perilaku spekulatif di aset berisiko karena pencarian yield, sehingga meningkatkan volatilitas pasar keuangan. Bank sentral harus menyeimbangkan dorongan likuiditas dengan stabilitas sistem keuangan.', '2026-03-28 14:30:19', '2026-03-28 14:30:19', NULL),
	(44, 'Bagaimana penggunaan quantitative easing (QE) berbeda dengan operasi pasar terbuka tradisional, dan apa efeknya terhadap ekspektasi inflasi?', 'QE melibatkan pembelian aset jangka panjang (bukan hanya surat berharga jangka pendek) untuk menambah likuiditas dan menurunkan suku bunga jangka panjang, berbeda dari operasi pasar terbuka yang biasanya jangka pendek. Efek QE tidak hanya meningkatkan uang beredar tetapi juga memengaruhi ekspektasi inflasi: investor melihat komitmen bank sentral untuk mempertahankan likuiditas tinggi sebagai sinyal bahwa inflasi akan kembali ke target, sehingga memengaruhi perilaku konsumsi dan investasi.', '2026-03-28 14:30:19', '2026-03-28 14:30:19', NULL),
	(45, 'Mengapa bank sentral menggunakan rasio cadangan wajib (reserve requirement ratio) sebagai alat kebijakan moneter, dan apa kelemahannya?', 'Rasio cadangan wajib menentukan persentase simpanan yang harus disimpan bank di bank sentral. Dengan menaikkan rasio, likuiditas berkurang, menahan kredit dan inflasi. Menurunkan rasio meningkatkan likuiditas dan mendorong pinjaman. Kelemahannya, perubahan rasio berdampak lambat, sulit disesuaikan cepat, dan bisa menimbulkan tekanan likuiditas mendadak jika perbankan tidak siap. Oleh karena itu, banyak bank sentral lebih mengandalkan suku bunga untuk transmisi moneter yang lebih halus.', '2026-03-28 14:30:19', '2026-03-28 14:30:19', NULL),
	(46, 'Jelaskan konsep lender of last resort dan mengapa perannya krusial selama krisis keuangan.', 'Lender of last resort adalah fungsi bank sentral memberi likuiditas darurat pada bank yang mengalami kesulitan sementara namun solvent. Tujuannya mencegah panic banking, run pada bank, dan penyebaran risiko sistemik. Tanpa peran ini, kegagalan satu bank dapat memicu kegagalan berantai. Namun, peran ini harus hati-hati agar tidak mendorong moral hazard, yaitu bank mengambil risiko berlebihan karena mengharapkan bailout.', '2026-03-28 14:30:19', '2026-03-28 14:30:19', NULL),
	(47, 'Bagaimana kebijakan forward guidance memengaruhi ekspektasi pasar dan perilaku ekonomi?', 'Forward guidance adalah komunikasi bank sentral mengenai arah masa depan suku bunga atau kebijakan moneter. Ini memengaruhi ekspektasi pasar: jika pelaku pasar yakin suku bunga akan tetap rendah, mereka lebih cenderung meminjam dan berinvestasi sekarang. Dengan demikian, forward guidance memperkuat transmisi kebijakan moneter tanpa harus segera mengubah suku bunga. Keberhasilan strategi ini bergantung pada kredibilitas bank sentral dan kejelasan komunikasi.', '2026-03-28 14:30:19', '2026-03-28 14:30:19', NULL),
	(48, 'Apa dampak dari kebijakan sterilization terhadap neraca bank sentral dan kurs mata uang?', 'Sterilisasi dilakukan ketika bank sentral menyerap atau menambah likuiditas untuk menetralkan efek intervensi valuta asing. Misalnya, membeli mata uang asing menambah cadangan devisa, tetapi bank sentral bisa melakukan penjualan obligasi domestik untuk menahan jumlah uang beredar. Dampaknya, neraca bank sentral membengkak, biaya operasi meningkat, dan nilai tukar stabil karena intervensi tidak menimbulkan inflasi domestik berlebih.', '2026-03-28 14:30:19', '2026-03-28 14:30:19', NULL),
	(49, 'Mengapa suku bunga acuan tidak selalu transmisi sempurna ke suku bunga kredit bank, dan faktor apa yang memengaruhi transmisi ini?', 'Transmisi suku bunga acuan ke kredit bank dipengaruhi oleh struktur pasar keuangan, likuiditas, risiko kredit, dan ekspektasi inflasi. Jika bank menghadapi risiko tinggi atau modal terbatas, perubahan suku bunga acuan mungkin tidak diteruskan sepenuhnya ke nasabah. Faktor lain termasuk persaingan antarbank, biaya operasional, dan ketergantungan bank pada sumber pendanaan non-bank. Hal ini membuat kebijakan moneter terkadang kurang efektif dalam mengatur konsumsi dan investasi.', '2026-03-28 14:30:19', '2026-03-28 14:30:19', NULL),
	(50, 'Jelaskan perbedaan antara monetary base dan broad money (M2/M3) serta relevansinya dalam pengendalian inflasi.', 'Monetary base (MB) mencakup uang tunai di sirkulasi dan cadangan bank di bank sentral; ini adalah basis penciptaan uang. Broad money (M2/M3) meliputi MB ditambah simpanan bank yang bisa digunakan untuk kredit dan investasi. Bank sentral mengontrol MB langsung melalui operasi pasar terbuka atau standing facilities, sementara M2/M3 bergerak tergantung perilaku bank dan publik. Mengelola MB efektif untuk stabilisasi jangka pendek, sedangkan M2/M3 lebih relevan untuk inflasi jangka menengah karena mencerminkan likuiditas total dalam ekonomi.', '2026-03-28 14:30:19', '2026-03-28 14:30:19', NULL),
	(51, 'Jelaskan bagaimana forward guidance dapat memengaruhi kurva imbal hasil obligasi pemerintah dan ekspektasi inflasi jangka panjang.', 'Forward guidance memengaruhi ekspektasi pasar dengan memberi sinyal tentang arah suku bunga masa depan. Jika bank sentral menyatakan suku bunga akan tetap rendah untuk jangka panjang, investor akan menyesuaikan permintaan obligasi, menurunkan imbal hasil jangka panjang. Hal ini juga menurunkan ekspektasi inflasi jangka panjang karena pasar mempercayai komitmen bank sentral untuk menjaga stabilitas harga, sehingga memengaruhi perilaku konsumsi dan investasi.', '2026-03-28 14:39:02', '2026-03-28 14:39:02', NULL),
	(52, 'Bagaimana penggunaan swap valuta asing oleh bank sentral dapat menjaga stabilitas nilai tukar dan likuiditas domestik?', 'Swap valuta asing memungkinkan bank sentral menukar mata uang asing dengan mata uang domestik sementara. Ini menambah likuiditas domestik atau menyerap kelebihan likuiditas sesuai kebutuhan. Dengan demikian, bank sentral dapat menstabilkan kurs mata uang dan menjaga suplai uang beredar agar tidak memicu volatilitas pasar uang dan inflasi. Intervensi ini biasanya bersifat sementara tetapi strategis selama krisis valuta.', '2026-03-28 14:39:02', '2026-03-28 14:39:02', NULL),
	(53, 'Mengapa bank sentral perlu menyeimbangkan antara independensi kebijakan moneter dan akuntabilitas terhadap pemerintah?', 'Independensi memungkinkan bank sentral fokus pada target inflasi dan stabilitas keuangan tanpa tekanan politik jangka pendek. Namun, bank sentral tetap harus akuntabel kepada publik dan legislatif agar kebijakan transparan dan kredibel. Keseimbangan ini penting karena independensi penuh tanpa akuntabilitas bisa menimbulkan kebijakan yang tidak sesuai kepentingan ekonomi nasional, sedangkan akuntabilitas berlebihan dapat mengurangi efektivitas kebijakan moneter.', '2026-03-28 14:39:02', '2026-03-28 14:39:02', NULL),
	(54, 'Jelaskan risiko yang timbul dari ekspansi neraca bank sentral dalam jangka panjang, terutama akibat quantitative easing.', 'Ekspansi neraca bank sentral melalui pembelian aset (QE) meningkatkan likuiditas dan menurunkan suku bunga. Namun, dalam jangka panjang, neraca besar dapat menimbulkan risiko inflasi jika likuiditas berlebih tidak terserap. Selain itu, bank sentral menghadapi risiko valuasi aset, biaya penarikan likuiditas di masa depan, dan potensi distorsi harga aset. Risiko ini menuntut strategi exit policy yang hati-hati agar tidak mengguncang pasar keuangan.', '2026-03-28 14:39:02', '2026-03-28 14:39:02', NULL),
	(55, 'Bagaimana kebijakan makroprudensial yang diterapkan bank sentral dapat memengaruhi transmisi kebijakan moneter?', 'Kebijakan makroprudensial seperti batas LTV, countercyclical capital buffer, atau loan-to-deposit ratio memengaruhi perilaku bank dalam memberikan kredit. Kebijakan ini dapat memperkuat atau melemahkan transmisi kebijakan moneter karena bank mungkin menahan atau mendorong pinjaman meskipun suku bunga berubah. Dengan demikian, koordinasi antara kebijakan moneter dan makroprudensial sangat penting untuk efektivitas stabilitas keuangan.', '2026-03-28 14:39:02', '2026-03-28 14:39:02', NULL),
	(56, 'Jelaskan bagaimana forward guidance yang tidak kredibel dapat memengaruhi ekspektasi inflasi dan stabilitas ekonomi.', 'Jika pasar meragukan komitmen bank sentral, forward guidance bisa gagal memengaruhi ekspektasi inflasi. Investor dan konsumen mungkin tetap menunda konsumsi atau investasi karena tidak percaya suku bunga akan tetap rendah, sehingga transmisi kebijakan moneter melemah. Kredibilitas adalah kunci: bank sentral harus konsisten dan transparan agar pasar mempercayai sinyal kebijakan yang diberikan.', '2026-03-28 14:39:02', '2026-03-28 14:39:02', NULL),
	(57, 'Bagaimana intervensi bank sentral di pasar valuta asing dapat berdampak pada neraca dan eksposur risiko mata uang?', 'Intervensi valuta asing melibatkan pembelian atau penjualan mata uang asing untuk menstabilkan nilai tukar. Ini menambah aset dan kewajiban di neraca bank sentral, menciptakan risiko nilai tukar dan potensi kerugian jika mata uang asing bergerak melawan posisi bank sentral. Manajemen risiko yang hati-hati dan strategi sterilisasi sering diperlukan untuk menahan dampak inflasi domestik dan volatilitas pasar.', '2026-03-28 14:39:02', '2026-03-28 14:39:02', NULL),
	(58, 'Jelaskan hubungan antara suku bunga kebijakan, inflasi inti, dan ekspektasi inflasi dalam konteks stabilitas harga jangka menengah.', 'Suku bunga kebijakan mempengaruhi biaya kredit, konsumsi, dan investasi, yang kemudian memengaruhi tekanan inflasi. Inflasi inti, yang mengecualikan harga volatile seperti energi dan pangan, digunakan untuk memproyeksikan tren inflasi jangka menengah. Ekspektasi inflasi menentukan perilaku pasar dan konsumen: jika ekspektasi stabil, inflasi aktual lebih mudah dikontrol. Bank sentral menggunakan semua indikator ini untuk menetapkan suku bunga yang menjaga stabilitas harga jangka menengah.', '2026-03-28 14:39:02', '2026-03-28 14:39:02', NULL),
	(59, 'Bagaimana penggunaan liquidity backstop oleh bank sentral dapat mencegah krisis perbankan sistemik?', 'Liquidity backstop adalah fasilitas yang memberi bank akses cepat ke likuiditas selama ketegangan pasar. Ini mencegah kegagalan satu bank memicu run pada bank lain dan risiko sistemik. Namun, fasilitas ini harus disertai syarat yang ketat untuk menghindari moral hazard. Peran backstop menjadi sangat krusial dalam menjaga kepercayaan pasar dan stabilitas sistem keuangan selama krisis.', '2026-03-28 14:39:02', '2026-03-28 14:39:02', NULL),
	(60, 'Jelaskan peran komunikasi bank sentral dalam membentuk ekspektasi inflasi dan mengurangi volatilitas pasar.', 'Komunikasi bank sentral, termasuk konferensi pers, laporan inflasi, dan forward guidance, membentuk ekspektasi pasar tentang arah suku bunga dan inflasi. Transparansi dan konsistensi dalam komunikasi meningkatkan kredibilitas, membantu mengurangi volatilitas pasar, dan memperkuat transmisi kebijakan moneter. Pasar yang percaya pada komitmen bank sentral akan menyesuaikan harga aset dan perilaku investasi lebih stabil, sehingga kebijakan menjadi lebih efektif.', '2026-03-28 14:39:02', '2026-03-28 14:39:02', NULL),
	(61, 'Jelaskan bagaimana forward guidance fleksibel dapat memengaruhi ekspektasi pasar selama periode ketidakpastian ekonomi tinggi.', 'Forward guidance fleksibel memungkinkan bank sentral memberi sinyal kondisi suku bunga yang dapat berubah tergantung data ekonomi. Hal ini membantu pasar menyesuaikan ekspektasi secara dinamis selama ketidakpastian, mendorong stabilitas harga aset, dan menjaga transmisi kebijakan moneter meskipun ekonomi mengalami guncangan. Kredibilitas komunikasi tetap kunci agar efeknya optimal.', '2026-03-28 14:45:32', '2026-03-28 14:45:32', NULL),
	(62, 'Bagaimana mekanisme central bank digital currency (CBDC) dapat memengaruhi transmisi kebijakan moneter?', 'CBDC memberikan bank sentral kontrol lebih langsung atas basis uang dan suku bunga kebijakan. Dengan CBDC, perubahan suku bunga dapat langsung diterapkan pada saldo digital publik, meningkatkan kecepatan transmisi moneter, mengurangi hambatan likuiditas, dan mempengaruhi konsumsi serta investasi dengan lebih presisi dibanding instrumen tradisional.', '2026-03-28 14:45:32', '2026-03-28 14:45:32', NULL),
	(63, 'Jelaskan bagaimana bank sentral dapat menggunakan interest on excess reserves (IOER) untuk menahan likuiditas berlebih di sistem perbankan.', 'IOER memberi insentif kepada bank untuk menahan cadangan lebih di bank sentral dengan membayar bunga atas kelebihan cadangan. Dengan cara ini, bank sentral dapat menahan likuiditas berlebih tanpa harus menjual aset di pasar, menjaga stabilitas suku bunga jangka pendek, dan mengurangi tekanan inflasi sementara menjaga fleksibilitas operasi.', '2026-03-28 14:45:32', '2026-03-28 14:45:32', NULL),
	(64, 'Bagaimana quantitative tightening berbeda dari quantitative easing, dan apa risiko utama yang terkait?', 'Quantitative tightening adalah kebalikan QE: bank sentral menjual aset atau menahan reinvestasi untuk menyerap likuiditas. Risiko utama termasuk kenaikan suku bunga pasar jangka panjang yang terlalu cepat, tekanan pada harga aset keuangan, dan potensi memperlambat pertumbuhan ekonomi jika tidak disesuaikan secara bertahap.', '2026-03-28 14:45:32', '2026-03-28 14:45:32', NULL),
	(65, 'Jelaskan peran swap lines internasional antar bank sentral dalam mencegah krisis likuiditas global.', 'Swap lines antar bank sentral memungkinkan pertukaran mata uang asing sementara untuk menjaga likuiditas global. Ini mencegah ketegangan pasar uang internasional, menstabilkan nilai tukar domestik, dan mendukung arus perdagangan serta pembiayaan lintas negara, sehingga risiko contagion finansial dapat diminimalkan selama krisis.', '2026-03-28 14:45:32', '2026-03-28 14:45:32', NULL),
	(66, 'Bagaimana forward guidance dapat memperkuat transmisi kebijakan moneter ketika suku bunga mendekati batas nol?', 'Ketika suku bunga mendekati nol, instrumen tradisional kurang efektif. Forward guidance memberi sinyal jangka panjang tentang suku bunga rendah atau stimulasi tambahan, mempengaruhi ekspektasi inflasi dan perilaku investasi, sehingga transmisi kebijakan tetap berjalan meski suku bunga nominal tidak dapat diturunkan lebih jauh.', '2026-03-28 14:45:32', '2026-03-28 14:45:32', NULL),
	(67, 'Jelaskan risiko moral hazard yang muncul akibat fasilitas lender of last resort, dan bagaimana bank sentral memitigasinya.', 'Memberi likuiditas darurat kepada bank dapat mendorong perilaku risk-taking karena bank tahu ada backstop. Bank sentral memitigasi moral hazard dengan syarat ketat, bunga tinggi untuk pinjaman darurat, dan audit ketat, sehingga fasilitas tetap melindungi stabilitas tanpa mendorong perilaku spekulatif berlebihan.', '2026-03-28 14:45:32', '2026-03-28 14:45:32', NULL),
	(68, 'Bagaimana kombinasi kebijakan moneter dan makroprudensial dapat digunakan untuk mencegah gelembung kredit?', 'Kebijakan moneter mempengaruhi biaya kredit, sedangkan kebijakan makroprudensial seperti batas LTV atau countercyclical capital buffer membatasi ekspansi kredit berlebihan. Kombinasi keduanya membantu menjaga pertumbuhan kredit sehat, mencegah gelembung aset, dan meminimalkan risiko krisis keuangan di masa depan.', '2026-03-28 14:45:32', '2026-03-28 14:45:32', NULL),
	(69, 'Jelaskan bagaimana ekspektasi inflasi dapat memengaruhi efektivitas suku bunga kebijakan bank sentral.', 'Jika publik dan pasar mempercayai target inflasi bank sentral, ekspektasi inflasi akan stabil, sehingga perubahan suku bunga lebih efektif mempengaruhi konsumsi, investasi, dan harga. Sebaliknya, ekspektasi tidak stabil melemahkan transmisi suku bunga dan bisa memicu fluktuasi inflasi yang lebih besar.', '2026-03-28 14:45:32', '2026-03-28 14:45:32', NULL),
	(70, 'Bagaimana intervensi bank sentral di pasar obligasi pemerintah dapat mempengaruhi kurva imbal hasil dan risiko fiskal?', 'Pembelian obligasi pemerintah menurunkan yield jangka panjang dan menekan biaya pembiayaan pemerintah. Namun, eksposur neraca bank sentral meningkat, sehingga risiko fiskal muncul jika nilai obligasi turun. Pengaruh ini juga memengaruhi alokasi aset pasar keuangan dan transmisi moneter jangka panjang.', '2026-03-28 14:45:32', '2026-03-28 14:45:32', NULL),
	(71, 'Jelaskan peran komunikasi bank sentral dalam mengelola volatilitas pasar selama periode ketidakpastian tinggi.', 'Komunikasi yang jelas dan konsisten memberikan sinyal tentang arah kebijakan moneter, ekspektasi inflasi, dan strategi intervensi. Hal ini membantu pelaku pasar membuat keputusan investasi lebih rasional, menurunkan volatilitas harga aset, dan memperkuat kredibilitas bank sentral sehingga transmisi kebijakan lebih efektif.', '2026-03-28 14:45:32', '2026-03-28 14:45:32', NULL),
	(72, 'Bagaimana bank sentral dapat menggunakan kebijakan suku bunga negatif untuk memacu ekonomi, dan risiko apa yang menyertainya?', 'Suku bunga negatif menekan biaya pinjaman, mendorong bank menyalurkan kredit lebih banyak, dan memacu konsumsi serta investasi. Risiko termasuk tekanan pada profitabilitas bank, perilaku risiko tinggi di pasar keuangan, dan potensi dampak negatif pada sistem pembayaran serta tabungan publik.', '2026-03-28 14:45:32', '2026-03-28 14:45:32', NULL),
	(73, 'Jelaskan bagaimana forward guidance dapat mempengaruhi keputusan investasi perusahaan jangka panjang.', 'Perusahaan merespons sinyal suku bunga masa depan dari forward guidance dalam merencanakan investasi modal. Jika suku bunga diproyeksikan rendah, biaya pendanaan lebih murah, meningkatkan proyek investasi jangka panjang, sementara ketidakpastian atau sinyal yang tidak konsisten dapat menunda keputusan dan mengurangi pertumbuhan ekonomi.', '2026-03-28 14:45:32', '2026-03-28 14:45:32', NULL),
	(74, 'Bagaimana quantitative easing memengaruhi ekspektasi inflasi dan struktur suku bunga dalam jangka menengah?', 'QE menambah likuiditas dan menurunkan yield obligasi jangka panjang, sehingga mempengaruhi biaya modal dan ekspektasi inflasi jangka menengah. Pasar melihat langkah ini sebagai komitmen bank sentral untuk mendukung ekonomi, menurunkan ekspektasi inflasi riil dan mendorong investasi serta konsumsi.', '2026-03-28 14:45:32', '2026-03-28 14:45:32', NULL),
	(75, 'Jelaskan bagaimana bank sentral dapat menyeimbangkan antara stabilitas nilai tukar dan inflasi domestik dalam konteks intervensi valuta asing.', 'Intervensi valuta asing dapat menstabilkan kurs, tetapi menambah atau menyerap likuiditas yang berpotensi memengaruhi inflasi. Bank sentral harus menyeimbangkan dampak terhadap harga domestik dan nilai tukar dengan sterilisasi, kebijakan suku bunga, dan koordinasi fiskal agar stabilitas makro tetap terjaga.', '2026-03-28 14:45:32', '2026-03-28 14:45:32', NULL),
	(76, 'Jelaskan bagaimana suku bunga acuan memengaruhi pinjaman bank dan konsumsi rumah tangga.', 'Suku bunga acuan menentukan biaya pinjaman antarbank, yang diteruskan ke suku bunga kredit. Kenaikan suku bunga menurunkan permintaan pinjaman dan konsumsi rumah tangga, sementara penurunan suku bunga mendorong kredit dan konsumsi. Efek ini membantu bank sentral mengatur inflasi dan pertumbuhan ekonomi.', '2026-03-28 14:52:49', '2026-03-28 14:52:49', NULL),
	(77, 'Bagaimana operasi pasar terbuka digunakan untuk mengontrol likuiditas sistem perbankan?', 'Bank sentral membeli atau menjual surat berharga pemerintah di pasar untuk menambah atau menyerap likuiditas. Pembelian menambah uang beredar, sementara penjualan menyerapnya. Mekanisme ini menjaga stabilitas suku bunga dan mendukung transmisi kebijakan moneter.', '2026-03-28 14:52:49', '2026-03-28 14:52:49', NULL),
	(78, 'Jelaskan peran cadangan wajib minimum (reserve requirement) dalam stabilisasi sistem perbankan.', 'Cadangan wajib minimum mengatur jumlah dana yang harus disimpan bank di bank sentral. Dengan menaikkan cadangan wajib, bank sentral menyerap likuiditas dan menahan ekspansi kredit; sebaliknya, penurunan cadangan wajib meningkatkan likuiditas dan mendorong pinjaman. Alat ini membantu menjaga stabilitas sistem keuangan.', '2026-03-28 14:52:49', '2026-03-28 14:52:49', NULL),
	(79, 'Bagaimana intervensi suku bunga memengaruhi ekspektasi inflasi di masyarakat?', 'Perubahan suku bunga acuan memberi sinyal tentang arah kebijakan moneter. Kenaikan suku bunga biasanya menurunkan ekspektasi inflasi, karena menekan permintaan, sementara penurunan suku bunga dapat meningkatkan ekspektasi inflasi melalui stimulasi konsumsi dan investasi.', '2026-03-28 14:52:49', '2026-03-28 14:52:49', NULL),
	(80, 'Jelaskan dampak kebijakan moneter ekspansif terhadap nilai tukar mata uang domestik.', 'Kebijakan moneter ekspansif, seperti menurunkan suku bunga atau membeli aset, menambah likuiditas dan cenderung menekan nilai tukar. Mata uang melemah karena perbedaan suku bunga internasional, yang bisa mendorong ekspor tetapi meningkatkan harga barang impor.', '2026-03-28 14:52:49', '2026-03-28 14:52:49', NULL),
	(81, 'Bagaimana forward guidance sederhana membantu menstabilkan ekspektasi pasar?', 'Forward guidance sederhana memberi sinyal tentang arah suku bunga masa depan. Pasar menyesuaikan ekspektasi inflasi dan biaya pinjaman, sehingga keputusan investasi dan konsumsi menjadi lebih stabil, memperkuat transmisi kebijakan moneter.', '2026-03-28 14:52:49', '2026-03-28 14:52:49', NULL),
	(82, 'Jelaskan hubungan antara quantitative easing dan harga aset finansial jangka panjang.', 'QE menambah likuiditas dan menurunkan suku bunga jangka panjang. Hal ini menaikkan harga obligasi dan aset finansial lainnya, karena investor mencari imbal hasil lebih tinggi di instrumen lain, sehingga memengaruhi portofolio dan alokasi aset secara luas.', '2026-03-28 14:52:49', '2026-03-28 14:52:49', NULL),
	(83, 'Bagaimana bank sentral dapat memanfaatkan swap valuta asing untuk menjaga stabilitas kurs?', 'Dengan swap valuta asing, bank sentral dapat menambah cadangan mata uang asing sementara, menstabilkan kurs, dan menghindari tekanan berlebih pada neraca perbankan. Mekanisme ini penting selama gejolak pasar internasional.', '2026-03-28 14:52:49', '2026-03-28 14:52:49', NULL),
	(84, 'Jelaskan fungsi likuiditas darurat (emergency liquidity facility) dalam sistem perbankan.', 'Fasilitas likuiditas darurat memberi bank akses sementara terhadap dana untuk memenuhi kebutuhan likuiditas mendadak. Ini mencegah kepanikan, menjaga stabilitas sistem perbankan, dan mengurangi risiko penularan krisis ke lembaga keuangan lain.', '2026-03-28 14:52:49', '2026-03-28 14:52:49', NULL),
	(85, 'Bagaimana independensi bank sentral memengaruhi kredibilitas kebijakan moneter?', 'Independensi memungkinkan bank sentral fokus pada stabilitas harga tanpa tekanan politik jangka pendek. Kredibilitas meningkat karena publik dan pasar percaya bahwa kebijakan ditujukan untuk tujuan jangka menengah, sehingga transmisi kebijakan lebih efektif.', '2026-03-28 14:52:49', '2026-03-28 14:52:49', NULL),
	(86, 'Jelaskan peran komunikasi bank sentral dalam membentuk ekspektasi inflasi.', 'Komunikasi yang jelas mengenai target inflasi, arah suku bunga, dan kebijakan moneter membantu masyarakat dan pasar membentuk ekspektasi inflasi. Ekspektasi yang stabil memperkuat efektivitas suku bunga dan mengurangi volatilitas harga aset.', '2026-03-28 14:52:49', '2026-03-28 14:52:49', NULL),
	(87, 'Bagaimana kebijakan suku bunga negatif memengaruhi profitabilitas bank?', 'Suku bunga negatif mendorong bank menyalurkan pinjaman lebih agresif, namun menekan margin bunga bersih karena cadangan berlebih di bank sentral dibayar bunga rendah atau negatif, sehingga profitabilitas bisa terdampak.', '2026-03-28 14:52:49', '2026-03-28 14:52:49', NULL),
	(88, 'Jelaskan bagaimana cadangan wajib minimum berbeda dari suku bunga kebijakan dalam transmisi moneter.', 'Cadangan wajib minimum langsung membatasi kemampuan bank menyalurkan kredit, sementara suku bunga kebijakan memengaruhi biaya pinjaman dan perilaku ekonomi secara tidak langsung. Keduanya mempengaruhi likuiditas dan transmisi moneter, tetapi melalui mekanisme yang berbeda.', '2026-03-28 14:52:49', '2026-03-28 14:52:49', NULL),
	(89, 'Bagaimana forward guidance jangka pendek berbeda dengan jangka panjang dalam mempengaruhi pasar?', 'Forward guidance jangka pendek memberi sinyal perubahan suku bunga dalam waktu dekat, sementara jangka panjang membentuk ekspektasi jangka menengah dan panjang, sehingga mempengaruhi keputusan investasi dan konsumsi yang berbeda-beda berdasarkan horizon waktu.', '2026-03-28 14:52:49', '2026-03-28 14:52:49', NULL),
	(90, 'Jelaskan hubungan antara operasi pasar terbuka dan stabilitas suku bunga antarbank.', 'Operasi pasar terbuka mengatur likuiditas sistem perbankan. Dengan membeli atau menjual surat berharga pemerintah, bank sentral memengaruhi penawaran uang di pasar antarbank, menjaga suku bunga stabil dan mendukung transmisi kebijakan moneter.', '2026-03-28 14:52:49', '2026-03-28 14:52:49', NULL),
	(91, 'Apa itu suku bunga acuan dan bagaimana fungsinya bagi ekonomi?', 'Suku bunga acuan adalah suku bunga yang ditetapkan bank sentral sebagai acuan bagi suku bunga pinjaman antarbank. Fungsinya adalah untuk mengendalikan likuiditas, mempengaruhi biaya kredit, dan membantu menjaga stabilitas inflasi serta pertumbuhan ekonomi. Suku bunga ini menjadi dasar bagi bank untuk menentukan suku bunga kredit dan deposito bagi masyarakat.', '2026-03-28 14:58:20', '2026-03-28 14:58:20', NULL),
	(92, 'Jelaskan apa yang dimaksud dengan cadangan wajib minimum.', 'Cadangan wajib minimum adalah persentase tertentu dari dana pihak ketiga yang harus disimpan oleh bank di bank sentral. Tujuannya untuk menjaga stabilitas sistem perbankan dan mencegah ekspansi kredit yang berlebihan. Dengan cadangan wajib minimum, bank sentral dapat mengatur jumlah uang yang beredar di masyarakat secara lebih efektif.', '2026-03-28 14:58:20', '2026-03-28 14:58:20', NULL),
	(93, 'Apa itu operasi pasar terbuka dan tujuan penggunaannya?', 'Operasi pasar terbuka adalah kegiatan bank sentral membeli atau menjual surat berharga pemerintah untuk menambah atau menyerap likuiditas. Tujuannya untuk menjaga stabilitas suku bunga dan memastikan transmisi kebijakan moneter berjalan efektif di seluruh sistem perbankan.', '2026-03-28 14:58:20', '2026-03-28 14:58:20', NULL),
	(94, 'Jelaskan apa yang dimaksud dengan forward guidance.', 'Forward guidance adalah komunikasi bank sentral tentang arah kebijakan moneter di masa depan, misalnya ekspektasi perubahan suku bunga. Tujuan utamanya adalah memberikan sinyal kepada pasar dan masyarakat agar dapat menyesuaikan keputusan konsumsi, investasi, dan pengelolaan risiko sesuai kebijakan yang akan datang.', '2026-03-28 14:58:20', '2026-03-28 14:58:20', NULL),
	(95, 'Apa itu quantitative easing (QE) dan bagaimana pengaruhnya terhadap likuiditas?', 'Quantitative easing adalah kebijakan membeli aset keuangan jangka panjang oleh bank sentral untuk menambah likuiditas di sistem perbankan. Dengan QE, suku bunga jangka panjang menurun, uang beredar meningkat, dan diharapkan dapat mendorong investasi dan konsumsi sehingga mendukung pertumbuhan ekonomi.', '2026-03-28 14:58:20', '2026-03-28 14:58:20', NULL),
	(96, 'Bagaimana intervensi valuta asing membantu menjaga stabilitas nilai tukar?', 'Intervensi valuta asing dilakukan oleh bank sentral untuk membeli atau menjual mata uang asing agar kurs domestik tetap stabil. Hal ini membantu menahan fluktuasi tajam yang dapat mengganggu perdagangan, investasi, dan stabilitas ekonomi.', '2026-03-28 14:58:20', '2026-03-28 14:58:20', NULL),
	(97, 'Jelaskan fungsi fasilitas likuiditas darurat bank sentral.', 'Fasilitas likuiditas darurat memberikan dana sementara kepada bank yang mengalami kekurangan likuiditas mendadak. Tujuannya untuk mencegah kepanikan, memastikan kelancaran sistem pembayaran, dan menjaga stabilitas perbankan secara keseluruhan.', '2026-03-28 14:58:20', '2026-03-28 14:58:20', NULL),
	(98, 'Apa yang dimaksud dengan independensi bank sentral?', 'Independensi bank sentral berarti bank sentral dapat menentukan kebijakan moneter tanpa tekanan politik jangka pendek. Hal ini penting untuk menjaga kredibilitas, memastikan fokus pada stabilitas harga, dan membuat kebijakan moneter lebih efektif.', '2026-03-28 14:58:20', '2026-03-28 14:58:20', NULL),
	(99, 'Bagaimana kebijakan suku bunga mempengaruhi konsumsi rumah tangga?', 'Kebijakan suku bunga mempengaruhi biaya kredit. Suku bunga tinggi membuat pinjaman lebih mahal sehingga konsumsi menurun, sementara suku bunga rendah menurunkan biaya pinjaman sehingga mendorong konsumsi rumah tangga. Mekanisme ini menjadi salah satu cara bank sentral mengatur pertumbuhan ekonomi dan inflasi.', '2026-03-28 14:58:20', '2026-03-28 14:58:20', NULL),
	(100, 'Jelaskan hubungan antara forward guidance dan ekspektasi inflasi.', 'Forward guidance memberi sinyal kepada pasar mengenai arah kebijakan moneter di masa depan. Dengan informasi ini, masyarakat dan pelaku pasar dapat membentuk ekspektasi inflasi yang lebih stabil, sehingga transmisi kebijakan moneter menjadi lebih efektif.', '2026-03-28 14:58:20', '2026-03-28 14:58:20', NULL),
	(101, 'Apa pengaruh quantitative easing terhadap harga aset finansial?', 'Dengan membeli aset jangka panjang, bank sentral menurunkan yield obligasi sehingga harga obligasi dan aset finansial lainnya cenderung naik. Hal ini mendorong investor untuk melakukan diversifikasi portofolio dan mendorong aktivitas pasar modal.', '2026-03-28 14:58:20', '2026-03-28 14:58:20', NULL),
	(102, 'Bagaimana swap valuta asing membantu perbankan selama gejolak pasar?', 'Swap valuta asing memberikan bank domestik akses sementara terhadap mata uang asing yang dibutuhkan. Hal ini membantu bank memenuhi kewajiban internasional dan menjaga stabilitas kurs saat terjadi gejolak pasar global.', '2026-03-28 14:58:20', '2026-03-28 14:58:20', NULL),
	(103, 'Apa tujuan cadangan wajib minimum bagi stabilitas sistem perbankan?', 'Cadangan wajib minimum memastikan bank memiliki simpanan tertentu di bank sentral, sehingga mengurangi risiko likuiditas berlebihan dan membantu menjaga kestabilan sistem perbankan serta transmisi kebijakan moneter.', '2026-03-28 14:58:20', '2026-03-28 14:58:20', NULL),
	(104, 'Jelaskan fungsi operasi pasar terbuka dalam stabilitas suku bunga antarbank.', 'Operasi pasar terbuka menambah atau menyerap likuiditas untuk menjaga suku bunga antarbank tetap stabil. Hal ini penting agar bank dapat meminjam dan menyalurkan kredit dengan biaya yang terukur, sehingga mendukung stabilitas ekonomi secara umum.', '2026-03-28 14:58:20', '2026-03-28 14:58:20', NULL),
	(105, 'Bagaimana kebijakan suku bunga negatif memengaruhi pinjaman dan profitabilitas bank?', 'Suku bunga negatif mendorong bank menyalurkan pinjaman lebih agresif karena simpanan di bank sentral memiliki bunga rendah atau negatif. Namun, hal ini dapat menekan margin bunga bersih dan mempengaruhi profitabilitas bank.', '2026-03-28 14:58:20', '2026-03-28 14:58:20', NULL),
	(106, 'Jelaskan hubungan antara inflasi dan pengangguran menurut Kurva Phillips.', 'Kurva Phillips menunjukkan hubungan terbalik antara inflasi dan pengangguran dalam jangka pendek. Ketika pengangguran rendah, tekanan upah naik sehingga inflasi meningkat. Sebaliknya, pengangguran tinggi cenderung menekan inflasi. Pemahaman ini penting untuk menilai trade-off kebijakan moneter.', '2026-03-28 15:15:05', '2026-03-28 15:15:05', NULL),
	(107, 'Bagaimana kebijakan moneter kontraktif memengaruhi output dan inflasi?', 'Kebijakan moneter kontraktif menaikkan suku bunga atau menyerap likuiditas untuk menekan inflasi. Akibatnya, biaya pinjaman meningkat, investasi dan konsumsi menurun, sehingga output jangka pendek bisa melambat. Hal ini menunjukkan dampak kebijakan terhadap pertumbuhan dan stabilitas harga.', '2026-03-28 15:15:05', '2026-03-28 15:15:05', NULL),
	(108, 'Jelaskan efek multiplier fiskal terhadap PDB.', 'Multiplier fiskal menunjukkan bagaimana perubahan pengeluaran pemerintah atau pajak memengaruhi PDB secara total. Misalnya, peningkatan pengeluaran pemerintah dapat memicu peningkatan konsumsi dan investasi, sehingga PDB naik lebih besar daripada pengeluaran awal, tergantung kecenderungan marginal untuk mengonsumsi.', '2026-03-28 15:15:05', '2026-03-28 15:15:05', NULL),
	(109, 'Bagaimana ekspektasi inflasi memengaruhi keputusan investasi perusahaan?', 'Perusahaan menyesuaikan rencana investasi berdasarkan ekspektasi inflasi. Jika inflasi diperkirakan tinggi, biaya modal meningkat dan ketidakpastian harga menekan investasi. Ekspektasi yang stabil mempermudah perencanaan dan meningkatkan efisiensi alokasi sumber daya.', '2026-03-28 15:15:05', '2026-03-28 15:15:05', NULL),
	(110, 'Jelaskan mekanisme transmisi kebijakan moneter melalui suku bunga.', 'Suku bunga memengaruhi konsumsi rumah tangga, investasi bisnis, dan harga aset. Kenaikan suku bunga membuat pinjaman lebih mahal, menekan permintaan agregat dan inflasi. Penurunan suku bunga sebaliknya mendorong permintaan, menunjukkan bagaimana kebijakan moneter ditransmisikan ke ekonomi riil.', '2026-03-28 15:15:05', '2026-03-28 15:15:05', NULL),
	(111, 'Bagaimana pengaruh kebijakan fiskal ekspansif terhadap neraca perdagangan?', 'Kebijakan fiskal ekspansif, seperti peningkatan belanja pemerintah atau pemotongan pajak, meningkatkan permintaan domestik. Hal ini dapat meningkatkan impor lebih cepat daripada ekspor, sehingga neraca perdagangan bisa memburuk sementara pertumbuhan ekonomi meningkat.', '2026-03-28 15:15:05', '2026-03-28 15:15:05', NULL),
	(112, 'Jelaskan hubungan antara cadangan devisa dan stabilitas nilai tukar.', 'Cadangan devisa yang cukup memungkinkan bank sentral menstabilkan nilai tukar melalui intervensi pasar valuta asing. Kekurangan cadangan membuat nilai tukar lebih rentan terhadap fluktuasi, berdampak pada perdagangan internasional dan inflasi impor.', '2026-03-28 15:15:05', '2026-03-28 15:15:05', NULL),
	(113, 'Bagaimana depresiasi mata uang memengaruhi inflasi impor?', 'Depresiasi mata uang membuat harga barang impor lebih mahal dalam mata uang domestik. Hal ini meningkatkan biaya produksi dan harga konsumen, sehingga mendorong inflasi impor. Pemahaman efek ini penting untuk kebijakan moneter dan pengendalian harga.', '2026-03-28 15:15:05', '2026-03-28 15:15:05', NULL),
	(114, 'Jelaskan dampak defisit anggaran terhadap suku bunga dan investasi swasta.', 'Defisit anggaran yang tinggi dapat menyebabkan pemerintah meminjam lebih banyak dari pasar modal, menekan suku bunga. Suku bunga yang lebih tinggi meningkatkan biaya pinjaman bagi sektor swasta, berpotensi menurunkan investasi dan memperlambat pertumbuhan ekonomi jangka menengah.', '2026-03-28 15:15:05', '2026-03-28 15:15:05', NULL),
	(115, 'Bagaimana tingkat tabungan domestik memengaruhi pertumbuhan ekonomi jangka panjang?', 'Tingkat tabungan yang tinggi menyediakan sumber pembiayaan untuk investasi, meningkatkan modal dan produktivitas. Hal ini mendukung pertumbuhan ekonomi jangka panjang. Sebaliknya, tabungan rendah membatasi investasi dan laju pertumbuhan potensial.', '2026-03-28 15:15:05', '2026-03-28 15:15:05', NULL),
	(116, 'Jelaskan konsep output potensial dan output aktual.', 'Output potensial adalah tingkat produksi maksimum yang dapat dicapai tanpa menimbulkan tekanan inflasi. Output aktual adalah produksi riil saat ini. Kesenjangan antara keduanya (output gap) digunakan untuk menilai tekanan inflasi dan efektivitas kebijakan ekonomi.', '2026-03-28 15:15:05', '2026-03-28 15:15:05', NULL),
	(117, 'Bagaimana ekspektasi rasional memengaruhi efektivitas kebijakan moneter?', 'Jika pelaku pasar memiliki ekspektasi rasional, mereka mengantisipasi kebijakan moneter dan menyesuaikan perilaku sebelum efek kebijakan terjadi. Hal ini dapat mengurangi efektivitas kebijakan jangka pendek, karena pasar sudah menginternalisasi perubahan suku bunga atau likuiditas.', '2026-03-28 15:15:05', '2026-03-28 15:15:05', NULL),
	(118, 'Jelaskan peran sektor luar negeri dalam menentukan PDB nasional.', 'Ekspor menambah permintaan domestik untuk barang dan jasa, sedangkan impor menguranginya. Neraca perdagangan dan aliran modal internasional memengaruhi output, inflasi, dan nilai tukar. Interaksi ini penting untuk memahami keterkaitan ekonomi domestik dengan global.', '2026-03-28 15:15:05', '2026-03-28 15:15:05', NULL),
	(119, 'Bagaimana shock permintaan agregat memengaruhi inflasi dan output?', 'Peningkatan permintaan agregat mendorong output dan harga naik, sedangkan penurunan permintaan menurunkan output dan inflasi. Analisis shock ini membantu memahami siklus bisnis dan respons kebijakan fiskal dan moneter.', '2026-03-28 15:15:05', '2026-03-28 15:15:05', NULL),
	(120, 'Jelaskan pengaruh suku bunga riil terhadap investasi jangka panjang.', 'Suku bunga riil memengaruhi biaya modal riil. Suku bunga tinggi menurunkan investasi karena proyek menjadi lebih mahal, sedangkan suku bunga rendah mendorong investasi dan pertumbuhan modal, memengaruhi kapasitas produksi jangka panjang.', '2026-03-28 15:15:05', '2026-03-28 15:15:05', NULL),
	(121, 'Bagaimana kebijakan moneter tidak konvensional (misalnya QE) memengaruhi pasar obligasi?', 'Kebijakan non-konvensional menurunkan yield obligasi dan meningkatkan harga aset, mendorong investor untuk diversifikasi ke aset berisiko lebih tinggi. Ini memengaruhi likuiditas pasar dan transmisi kebijakan moneter ke ekonomi riil.', '2026-03-28 15:15:05', '2026-03-28 15:15:05', NULL),
	(122, 'Jelaskan hubungan antara inflasi inti dan inflasi headline.', 'Inflasi headline mencakup semua harga, termasuk energi dan pangan, yang volatil. Inflasi inti mengecualikan komponen tersebut, memberikan indikasi tren harga jangka menengah. Perbedaan ini penting untuk kebijakan moneter yang stabil dan prediksi inflasi.', '2026-03-28 15:15:05', '2026-03-28 15:15:05', NULL),
	(123, 'Bagaimana pengaruh kenaikan harga minyak dunia terhadap inflasi domestik?', 'Kenaikan harga minyak meningkatkan biaya energi, produksi, dan transportasi, yang diteruskan ke harga konsumen. Hal ini mendorong inflasi domestik, mempengaruhi daya beli, dan menuntut respons kebijakan moneter untuk menjaga stabilitas harga.', '2026-03-28 15:15:05', '2026-03-28 15:15:05', NULL),
	(124, 'Jelaskan dampak depresiasi mata uang terhadap ekspor dan impor.', 'Depresiasi membuat barang ekspor lebih murah bagi luar negeri sehingga ekspor meningkat, sementara impor menjadi lebih mahal, mengurangi volume impor. Efek ini memengaruhi neraca perdagangan, inflasi, dan keseimbangan ekonomi makro.', '2026-03-28 15:15:05', '2026-03-28 15:15:05', NULL),
	(125, 'Apa itu Produk Domestik Bruto (PDB) dan bagaimana fungsinya?', 'Produk Domestik Bruto (PDB) adalah total nilai semua barang dan jasa yang dihasilkan di suatu negara dalam periode tertentu. PDB digunakan untuk mengukur ukuran ekonomi, pertumbuhan ekonomi, dan kesejahteraan masyarakat. PDB juga membantu pemerintah dalam merancang kebijakan fiskal dan moneter.', '2026-03-28 15:22:37', '2026-03-28 15:22:37', NULL),
	(126, 'Jelaskan perbedaan antara inflasi dan deflasi.', 'Inflasi adalah kenaikan umum harga barang dan jasa secara terus-menerus, sedangkan deflasi adalah penurunan umum harga. Inflasi menurunkan daya beli jika terlalu tinggi, sementara deflasi dapat memperlambat konsumsi dan investasi. Memahami perbedaan ini penting untuk kebijakan ekonomi.', '2026-03-28 15:22:37', '2026-03-28 15:22:37', NULL),
	(127, 'Apa itu pengangguran dan bagaimana pengaruhnya terhadap ekonomi?', 'Pengangguran adalah kondisi ketika tenaga kerja yang siap bekerja tidak mendapatkan pekerjaan. Tingkat pengangguran yang tinggi menurunkan pendapatan rumah tangga dan konsumsi, memperlambat pertumbuhan ekonomi, serta bisa meningkatkan beban pemerintah melalui bantuan sosial.', '2026-03-28 15:22:37', '2026-03-28 15:22:37', NULL),
	(128, 'Jelaskan apa yang dimaksud dengan tabungan nasional.', 'Tabungan nasional adalah total tabungan yang dilakukan oleh rumah tangga, perusahaan, dan pemerintah dalam suatu negara. Tabungan ini menjadi sumber pembiayaan investasi, mendukung pertumbuhan ekonomi jangka panjang, dan mempengaruhi stabilitas fiskal.', '2026-03-28 15:22:37', '2026-03-28 15:22:37', NULL),
	(129, 'Apa yang dimaksud dengan konsumsi rumah tangga?', 'Konsumsi rumah tangga adalah pengeluaran masyarakat untuk barang dan jasa sehari-hari, seperti makanan, pakaian, dan transportasi. Konsumsi merupakan komponen terbesar dari permintaan agregat dan menjadi indikator kesehatan ekonomi.', '2026-03-28 15:22:37', '2026-03-28 15:22:37', NULL),
	(130, 'Jelaskan perbedaan antara defisit dan surplus anggaran.', 'Defisit anggaran terjadi ketika pengeluaran pemerintah melebihi penerimaan, sedangkan surplus anggaran terjadi ketika penerimaan melebihi pengeluaran. Defisit dapat meningkatkan utang publik, sementara surplus dapat digunakan untuk menurunkan utang atau menambah investasi pemerintah.', '2026-03-28 15:22:37', '2026-03-28 15:22:37', NULL),
	(131, 'Apa itu neraca perdagangan?', 'Neraca perdagangan adalah perbedaan nilai ekspor dan impor suatu negara dalam periode tertentu. Surplus perdagangan terjadi jika ekspor lebih besar dari impor, sedangkan defisit terjadi jika impor lebih besar. Neraca perdagangan mempengaruhi nilai tukar dan stabilitas ekonomi makro.', '2026-03-28 15:22:37', '2026-03-28 15:22:37', NULL),
	(132, 'Jelaskan apa yang dimaksud dengan permintaan agregat.', 'Permintaan agregat adalah total permintaan barang dan jasa di suatu negara pada tingkat harga tertentu dan dalam periode tertentu. Komponennya meliputi konsumsi, investasi, pengeluaran pemerintah, dan net ekspor. Permintaan agregat memengaruhi output, harga, dan inflasi.', '2026-03-28 15:22:37', '2026-03-28 15:22:37', NULL),
	(133, 'Apa itu penawaran agregat?', 'Penawaran agregat adalah total barang dan jasa yang diproduksi oleh semua produsen dalam suatu negara pada tingkat harga tertentu. Penawaran agregat dipengaruhi oleh faktor produksi, teknologi, dan biaya input. Analisis penawaran agregat membantu memahami inflasi dan pertumbuhan ekonomi.', '2026-03-28 15:22:37', '2026-03-28 15:22:37', NULL),
	(134, 'Jelaskan pengaruh suku bunga terhadap investasi.', 'Suku bunga tinggi meningkatkan biaya pinjaman sehingga menurunkan investasi, sedangkan suku bunga rendah menurunkan biaya pinjaman dan mendorong investasi. Suku bunga adalah salah satu instrumen utama kebijakan moneter dalam memengaruhi ekonomi riil.', '2026-03-28 15:22:37', '2026-03-28 15:22:37', NULL),
	(135, 'Apa itu defisit fiskal?', 'Defisit fiskal terjadi ketika pengeluaran pemerintah lebih besar daripada pendapatan dari pajak dan sumber lainnya. Defisit ini biasanya dibiayai melalui utang publik. Defisit fiskal berpengaruh terhadap stabilitas ekonomi dan suku bunga di pasar modal.', '2026-03-28 15:22:37', '2026-03-28 15:22:37', NULL),
	(136, 'Jelaskan peran bank sentral dalam ekonomi.', 'Bank sentral mengatur jumlah uang beredar, mengendalikan inflasi, menjaga stabilitas nilai tukar, dan memastikan sistem perbankan tetap stabil. Bank sentral juga menetapkan suku bunga acuan yang mempengaruhi seluruh perekonomian.', '2026-03-28 15:22:37', '2026-03-28 15:22:37', NULL),
	(137, 'Apa yang dimaksud dengan inflasi biaya (cost-push inflation)?', 'Inflasi biaya terjadi ketika harga barang dan jasa naik karena meningkatnya biaya produksi, seperti upah, harga energi, atau bahan baku. Inflasi jenis ini dapat menurunkan daya beli masyarakat dan mempengaruhi laba perusahaan.', '2026-03-28 15:22:37', '2026-03-28 15:22:37', NULL),
	(138, 'Jelaskan inflasi permintaan (demand-pull inflation).', 'Inflasi permintaan terjadi ketika permintaan agregat melebihi kapasitas produksi, sehingga harga barang dan jasa naik. Biasanya terjadi pada periode pertumbuhan ekonomi tinggi dengan konsumsi dan investasi yang meningkat.', '2026-03-28 15:22:37', '2026-03-28 15:22:37', NULL),
	(139, 'Apa itu pengeluaran pemerintah dalam konteks PDB?', 'Pengeluaran pemerintah adalah seluruh belanja negara untuk barang dan jasa, termasuk infrastruktur, gaji pegawai negeri, dan layanan publik. Komponen ini masuk dalam permintaan agregat dan memengaruhi pertumbuhan ekonomi.', '2026-03-28 15:22:37', '2026-03-28 15:22:37', NULL),
	(140, 'Jelaskan apa yang dimaksud dengan neraca pembayaran.', 'Neraca pembayaran adalah catatan seluruh transaksi ekonomi antara suatu negara dan dunia luar dalam periode tertentu, termasuk perdagangan barang/jasa, investasi, dan aliran modal. Neraca ini membantu menilai keseimbangan ekonomi dan posisi eksternal negara.', '2026-03-28 15:22:37', '2026-03-28 15:22:37', NULL),
	(141, 'Apa itu pertumbuhan ekonomi?', 'Pertumbuhan ekonomi adalah peningkatan kapasitas produksi barang dan jasa suatu negara dari waktu ke waktu. Diukur dengan pertumbuhan PDB, pertumbuhan ekonomi mencerminkan kemajuan ekonomi, peningkatan pendapatan, dan standar hidup masyarakat.', '2026-03-28 15:22:37', '2026-03-28 15:22:37', NULL),
	(142, 'Jelaskan pengaruh inflasi terhadap daya beli masyarakat.', 'Inflasi menurunkan daya beli karena harga barang dan jasa naik sementara pendapatan nominal tetap. Inflasi tinggi yang tidak terkendali dapat mengurangi konsumsi dan memperlambat pertumbuhan ekonomi.', '2026-03-28 15:22:37', '2026-03-28 15:22:37', NULL),
	(143, 'Bagaimana mekanisme transmisi kebijakan moneter memengaruhi output dan harga?', 'Transmisi kebijakan moneter terjadi ketika perubahan suku bunga acuan atau likuiditas bank sentral memengaruhi keputusan konsumsi, investasi, dan harga. Mekanisme ini memengaruhi permintaan agregat, pertumbuhan ekonomi, dan inflasi melalui biaya pinjaman, ekspektasi, dan likuiditas pasar.', '2026-03-28 15:26:54', '2026-03-28 15:26:54', NULL),
	(144, 'Jelaskan hubungan antara pengeluaran pemerintah dan multiplikator fiskal.', 'Pengeluaran pemerintah dapat mendorong permintaan agregat lebih besar daripada nilai awal belanja melalui efek multiplier. Setiap tambahan belanja pemerintah meningkatkan pendapatan rumah tangga, yang kemudian meningkatkan konsumsi dan memicu pertumbuhan ekonomi tambahan.', '2026-03-28 15:26:54', '2026-03-28 15:26:54', NULL),
	(145, 'Bagaimana inflasi memengaruhi tingkat suku bunga riil dan keputusan investasi?', 'Inflasi yang tinggi mengurangi suku bunga riil (nominal dikurangi inflasi), sehingga mempengaruhi insentif investasi. Investor akan menuntut pengembalian lebih tinggi untuk menutupi penurunan daya beli, yang dapat menekan investasi riil dan mempengaruhi pertumbuhan ekonomi.', '2026-03-28 15:26:54', '2026-03-28 15:26:54', NULL),
	(146, 'Jelaskan dampak depresiasi mata uang terhadap neraca perdagangan dan inflasi.', 'Depresiasi meningkatkan harga impor dan menurunkan harga ekspor relatif, yang dapat mendorong ekspor dan menekan impor, memperbaiki neraca perdagangan. Namun, harga barang impor naik, sehingga inflasi domestik dapat meningkat, mempengaruhi daya beli masyarakat.', '2026-03-28 15:26:54', '2026-03-28 15:26:54', NULL),
	(147, 'Bagaimana perubahan ekspektasi inflasi memengaruhi permintaan agregat?', 'Jika masyarakat mengantisipasi inflasi tinggi, mereka cenderung meningkatkan konsumsi sekarang untuk menghindari harga lebih tinggi di masa depan. Hal ini meningkatkan permintaan agregat saat ini dan dapat mempercepat terjadinya inflasi.', '2026-03-28 15:26:54', '2026-03-28 15:26:54', NULL),
	(148, 'Jelaskan hubungan antara pengangguran dan inflasi dalam kurva Phillips.', 'Kurva Phillips menunjukkan trade-off jangka pendek antara inflasi dan pengangguran. Pengangguran rendah cenderung menaikkan inflasi karena upah dan permintaan meningkat, sementara pengangguran tinggi menekan inflasi. Hubungan ini membantu bank sentral dalam menetapkan kebijakan suku bunga.', '2026-03-28 15:26:54', '2026-03-28 15:26:54', NULL),
	(149, 'Bagaimana neraca pembayaran memengaruhi nilai tukar dan kebijakan moneter?', 'Neraca pembayaran yang defisit meningkatkan tekanan terhadap mata uang domestik, mendorong depresiasi. Bank sentral dapat menyesuaikan suku bunga atau intervensi pasar valuta asing untuk menstabilkan kurs dan mendukung stabilitas ekonomi secara keseluruhan.', '2026-03-28 15:26:54', '2026-03-28 15:26:54', NULL),
	(150, 'Jelaskan peran cadangan devisa dalam menghadapi gejolak eksternal.', 'Cadangan devisa memungkinkan bank sentral melakukan intervensi valuta asing untuk menstabilkan nilai tukar saat terjadi gejolak eksternal. Cadangan yang cukup memberikan kepercayaan pasar, mendukung stabilitas ekonomi, dan meminimalkan risiko krisis keuangan.', '2026-03-28 15:26:54', '2026-03-28 15:26:54', NULL),
	(151, 'Bagaimana quantitative easing memengaruhi harga aset finansial dan ekonomi riil?', 'QE menambah likuiditas di sistem keuangan, menurunkan suku bunga jangka panjang, dan mendorong harga obligasi dan aset finansial naik. Hal ini dapat menurunkan biaya modal, mendorong investasi dan konsumsi, sehingga mendukung pertumbuhan ekonomi riil.', '2026-03-28 15:26:54', '2026-03-28 15:26:54', NULL),
	(152, 'Jelaskan perbedaan antara kebijakan fiskal ekspansif dan kontraktif.', 'Kebijakan fiskal ekspansif meningkatkan pengeluaran pemerintah atau menurunkan pajak untuk mendorong permintaan agregat, sementara kebijakan kontraktif mengurangi pengeluaran atau menaikkan pajak untuk menurunkan tekanan inflasi. Pemilihan kebijakan bergantung pada kondisi ekonomi saat itu.', '2026-03-28 15:26:54', '2026-03-28 15:26:54', NULL),
	(153, 'Bagaimana forward guidance mempengaruhi ekspektasi pasar dan transmisi kebijakan?', 'Forward guidance memberi sinyal arah kebijakan moneter di masa depan, mempengaruhi ekspektasi suku bunga dan inflasi. Pasar menyesuaikan harga aset dan keputusan investasi sesuai ekspektasi, sehingga transmisi kebijakan moneter menjadi lebih efektif.', '2026-03-28 15:26:54', '2026-03-28 15:26:54', NULL),
	(154, 'Jelaskan efek fluktuasi harga komoditas global terhadap inflasi domestik.', 'Kenaikan harga komoditas seperti energi dan pangan meningkatkan biaya produksi dan harga barang di dalam negeri, memicu inflasi. Penurunan harga komoditas menurunkan tekanan inflasi, memengaruhi daya beli, konsumsi, dan kebijakan moneter.', '2026-03-28 15:26:54', '2026-03-28 15:26:54', NULL),
	(155, 'Bagaimana perubahan suku bunga acuan memengaruhi nilai tukar dan ekspor?', 'Suku bunga tinggi menarik modal asing, memperkuat mata uang domestik dan menekan ekspor karena harga lebih mahal di pasar internasional. Suku bunga rendah menurunkan nilai tukar dan mendorong ekspor, tetapi bisa meningkatkan inflasi impor.', '2026-03-28 15:26:54', '2026-03-28 15:26:54', NULL),
	(156, 'Jelaskan hubungan antara investasi swasta, tabungan nasional, dan pertumbuhan ekonomi.', 'Investasi swasta memerlukan pembiayaan dari tabungan nasional. Tabungan yang cukup menurunkan biaya modal dan meningkatkan investasi, yang pada gilirannya mendorong pertumbuhan ekonomi. Kekurangan tabungan nasional dapat memaksa negara mengandalkan utang luar negeri.', '2026-03-28 15:26:54', '2026-03-28 15:26:54', NULL),
	(157, 'Bagaimana kebijakan moneter kontraktif dapat menekan inflasi?', 'Dengan menaikkan suku bunga atau menyerap likuiditas melalui operasi pasar terbuka, bank sentral mengurangi konsumsi dan investasi, menurunkan permintaan agregat, dan mencegah kenaikan harga yang cepat, sehingga inflasi dapat ditekan.', '2026-03-28 15:26:54', '2026-03-28 15:26:54', NULL),
	(158, 'Jelaskan dampak defisit fiskal yang berkepanjangan terhadap ekonomi.', 'Defisit fiskal jangka panjang meningkatkan utang publik, menekan ruang fiskal untuk pengeluaran produktif, dan dapat meningkatkan suku bunga. Hal ini dapat menurunkan investasi swasta, memperlambat pertumbuhan ekonomi, dan meningkatkan risiko krisis fiskal.', '2026-03-28 15:26:54', '2026-03-28 15:26:54', NULL),
	(159, 'Bagaimana kebijakan suku bunga negatif memengaruhi likuiditas dan perilaku bank?', 'Suku bunga negatif mendorong bank menyalurkan pinjaman lebih agresif karena menyimpan dana di bank sentral menjadi tidak menguntungkan. Namun, hal ini dapat menekan margin bunga bersih dan mempengaruhi profitabilitas perbankan.', '2026-03-28 15:26:54', '2026-03-28 15:26:54', NULL),
	(160, 'Jelaskan hubungan antara inflasi inti dan inflasi keseluruhan.', 'Inflasi inti menghapus komponen harga yang sangat volatile, seperti pangan dan energi, untuk menangkap tren inflasi yang lebih stabil. Inflasi inti memberikan panduan bagi bank sentral untuk kebijakan moneter, sedangkan inflasi keseluruhan mencerminkan harga yang sebenarnya dibayar masyarakat.', '2026-03-28 15:26:54', '2026-03-28 15:26:54', NULL),
	(161, 'Bagaimana mekanisme pengaruh nilai tukar terhadap inflasi impor?', 'Depresiasi mata uang domestik membuat harga barang impor lebih mahal, sehingga meningkatkan inflasi impor. Apreciasi sebaliknya menurunkan harga impor dan dapat menekan inflasi, memengaruhi daya beli dan kebijakan moneter.', '2026-03-28 15:26:54', '2026-03-28 15:26:54', NULL),
	(162, 'Jelaskan dampak penurunan konsumsi rumah tangga terhadap pertumbuhan ekonomi.', 'Penurunan konsumsi rumah tangga mengurangi permintaan agregat, menurunkan output dan pertumbuhan ekonomi, serta dapat meningkatkan risiko resesi jika konsumsi tetap rendah dalam periode panjang.', '2026-03-28 15:26:54', '2026-03-28 15:26:54', NULL),
	(163, 'Bagaimana kebijakan fiskal ekspansif dapat memicu inflasi jika kapasitas produksi terbatas?', 'Jika pengeluaran pemerintah meningkat melebihi kapasitas produksi potensial, permintaan agregat lebih tinggi daripada penawaran agregat, sehingga mendorong harga naik dan memicu inflasi. Hal ini disebut inflasi permintaan.', '2026-03-28 15:26:54', '2026-03-28 15:26:54', NULL),
	(164, 'Jelaskan peran ekspektasi inflasi dalam penetapan upah dan harga oleh perusahaan.', 'Jika perusahaan dan pekerja memperkirakan inflasi tinggi, mereka akan menyesuaikan harga dan upah lebih tinggi, yang dapat menciptakan spiral harga-upah. Ekspektasi ini penting bagi bank sentral dalam menetapkan kebijakan moneter untuk menstabilkan harga.', '2026-03-28 15:26:54', '2026-03-28 15:26:54', NULL);
INSERT INTO `quizzes` (`id`, `uuid`, `title`, `description`, `is_premium`, `start_at`, `end_at`, `duration_minutes`, `created_at`, `updated_at`, `deleted_at`) VALUES
	(12, '5c8c0fbd-2ab6-11f1-852c-005056c00001', 'Kebijakan Bank Sentral: Teori & Praktik Level Tinggi', 'Kuis ini menantang peserta untuk memahami konsep lanjutan kebijakan bank sentral, termasuk transmisi moneter, forward guidance, quantitative easing, suku bunga negatif, dan intervensi valuta asing. Soal-soal HOTs dirancang untuk melatih kemampuan analisis, evaluasi kebijakan, dan penerapan teori dalam konteks nyata. Peserta harus mampu menghubungkan instrumen kebijakan dengan dampaknya pada inflasi, nilai tukar, likuiditas, dan stabilitas sistem perbankan.', 1, NULL, NULL, 60, '2026-03-28 14:56:55', '2026-03-28 14:56:55', NULL),
	(13, '5c8c20d0-2ab6-11f1-852c-005056c00001', 'Transmisi Moneter & Stabilitas Ekonomi', 'Kuis ini fokus pada pemahaman mekanisme transmisi moneter dan stabilitas ekonomi. Peserta akan diuji mengenai suku bunga acuan, cadangan wajib minimum, operasi pasar terbuka, dan forward guidance. Deskripsi soal panjang memberikan konteks nyata sehingga peserta dapat menganalisis hubungan antar instrumen moneter dan dampaknya terhadap konsumsi, investasi, dan ekspektasi inflasi.', 0, NULL, NULL, 45, '2026-03-28 14:56:55', '2026-03-28 14:56:55', NULL),
	(14, '5c8c26f7-2ab6-11f1-852c-005056c00001', 'Instrumen Kebijakan Bank Sentral: Analisis Mendalam', 'Kuis ini mengajak peserta untuk menilai efektivitas berbagai instrumen kebijakan bank sentral, termasuk quantitative tightening, fasilitas lender of last resort, dan swap valuta asing. Soal-soal dirancang untuk menguji kemampuan evaluasi kebijakan, analisis risiko moral hazard, dan interaksi antara kebijakan moneter dan makroprudensial.', 1, NULL, NULL, 50, '2026-03-28 14:56:55', '2026-03-28 14:56:55', NULL),
	(15, '5c8c29a1-2ab6-11f1-852c-005056c00001', 'Ekspektasi Inflasi & Dampak Kebijakan Moneter', 'Kuis ini menguji pemahaman peserta tentang bagaimana kebijakan bank sentral memengaruhi ekspektasi inflasi, harga aset, dan keputusan investasi. Peserta harus mampu menganalisis forward guidance, QE, dan intervensi suku bunga serta hubungannya dengan stabilitas ekonomi jangka menengah dan panjang.', 0, NULL, NULL, 40, '2026-03-28 14:56:55', '2026-03-28 14:56:55', NULL),
	(16, '5c8c2b77-2ab6-11f1-852c-005056c00001', 'Kebijakan Moneter dalam Konteks Makroekonomi Global', 'Kuis ini dirancang untuk menguji pemahaman hubungan antara kebijakan bank sentral domestik dengan stabilitas ekonomi global. Soal mencakup dampak suku bunga, QE, swap valuta asing, dan forward guidance terhadap nilai tukar, perdagangan internasional, dan likuiditas sistem keuangan. Peserta diharapkan dapat mengintegrasikan konsep makro dengan praktik kebijakan moneter global.', 1, NULL, NULL, 55, '2026-03-28 14:56:55', '2026-03-28 14:56:55', NULL),
	(17, '5445e9c0-2ab8-11f1-852c-005056c00001', 'Dasar-dasar Ekonomi Makro', 'Kuis ini membahas konsep-konsep fundamental dalam ekonomi makro, termasuk pertumbuhan ekonomi, inflasi, pengangguran, dan kebijakan fiskal serta moneter. Cocok untuk menguji pemahaman dasar dan kemampuan analisis hubungan antarvariabel makroekonomi.', 0, NULL, NULL, 15, '2026-03-28 15:11:00', '2026-03-28 15:11:00', NULL),
	(18, '5445f6d2-2ab8-11f1-852c-005056c00001', 'Kebijakan Moneter dan Fiskal', 'Kuis ini fokus pada instrumen kebijakan moneter dan fiskal, serta dampaknya terhadap perekonomian. Peserta akan diuji pada kemampuan menganalisis efek perubahan suku bunga, pengeluaran pemerintah, dan pajak terhadap pertumbuhan, inflasi, dan pengangguran.', 0, NULL, NULL, 20, '2026-03-28 15:11:00', '2026-03-28 15:11:00', NULL),
	(19, '5445f92f-2ab8-11f1-852c-005056c00001', 'Inflasi dan Stabilitas Harga', 'Kuis ini mengeksplorasi konsep inflasi, deflasi, dan stabilitas harga. Soal mencakup penyebab inflasi, pengukuran indeks harga, serta strategi pemerintah dan bank sentral dalam menjaga keseimbangan harga agar perekonomian tetap stabil.', 0, NULL, NULL, 15, '2026-03-28 15:11:00', '2026-03-28 15:11:00', NULL),
	(20, '5445fa6b-2ab8-11f1-852c-005056c00001', 'Pertumbuhan Ekonomi dan Siklus Bisnis', 'Kuis ini membahas faktor-faktor yang memengaruhi pertumbuhan ekonomi jangka panjang, serta dinamika siklus bisnis. Peserta akan diuji pada pemahaman tentang investasi, tabungan, produktivitas, dan mekanisme ekspansi-kontraksi ekonomi.', 0, NULL, NULL, 20, '2026-03-28 15:11:00', '2026-03-28 15:11:00', NULL),
	(21, '5445fbd2-2ab8-11f1-852c-005056c00001', 'Pengangguran dan Pasar Tenaga Kerja', 'Kuis ini menekankan pada konsep pengangguran, jenis-jenisnya, serta dampaknya terhadap perekonomian. Soal mencakup analisis kebijakan tenaga kerja, pengaruh inflasi terhadap upah riil, dan hubungan antara pengangguran dan pertumbuhan ekonomi.', 0, NULL, NULL, 15, '2026-03-28 15:11:00', '2026-03-28 15:11:00', NULL);
